INSERT INTO sms (body, sender, created, scheduled_send_at) VALUES ('SGLs!\r\n\r\nJust so you know - the latest notes and study are both up on the website. Praying for your groups this week as you continue to sit in God\'s Word. \r\nhttps://www.gracechurch.example.org/leaders-notesresources\r\n\r\nAlso - if you haven\'t been keeping up-to-date, could you please mark Jethro? Groups are growing, and lots of new people are joining church, so it\'s very helpful to have an accurate lay of the land to know the best way forward. Thanks!\r\n\r\nBlessings,\r\n ', 38, '2023-07-31 14:50:24', NULL);
