INSERT INTO sms (body, sender, created, scheduled_send_at) VALUES ('Gents! church\'s ManUp was postponed earlier this year but our hope is to head away at the end of 2022. \r\n\r\nWe are keen to get as many of us away together.\r\nSo, could you please indicate what weekend works best for you out of the below options AND whether you\'d prefer camping or cabin accomo scenario. \r\n\r\nA) 28-30 Oct\r\nB) 25-27 Nov\r\nC) 2-4 Dec\r\n\r\nThanks tigers. \r\n', 38, '2022-05-10 12:51:21', NULL);
