INSERT INTO sms (body, sender, created, scheduled_send_at) VALUES ('Gents! Just wanted to get church\'s Man Up Weekend on your radar.\r\n25-27 March up at Sandbar Campground. Cracker of a place and only 55 mins up the coast from Bayview. \r\nA chance to chill, chat, fish, explore and swim. \r\nWe would love to see you there. Regos will open towards the end of Feb. \r\nWhack that sucker into your calendars! \r\nBless ya\r\n (manliest pastor at church)', 38, '2022-02-04 11:30:43', NULL);
