INSERT INTO sms (body, sender, created, scheduled_send_at) VALUES ('Gents. A group of guys from church are heading up to Sandbar on May 26-28 to camp. Would love you to come if you\'re up for it. Book yourself in on the link below. \r\nIf you have booked and are coming, I would love you to let me know - I\'m extroverted, so if I end up being there by myself, it will be a nightmare...\r\nBlessings,\r\n\r\n\r\nhttps://www.nationalparks.nsw.gov.au/camping-and-accommodation/campgrounds/kylies-beach-campground', 38, '2023-05-17 13:59:10', NULL);
