INSERT INTO sms (body, sender, created, scheduled_send_at) VALUES ('Good morning church!\r\nJust a reminder that we are outside under the COLA this arvo. \r\nHere is the link to the online program: \r\nhttps://www.gracechurch.example.org/summersessions\r\n\r\nWe will also have some printouts of the songs for those without smartphones - so look for them at the Welcoming Table. \r\nWe would love it if you brought along your Bibles and a camping chair (if you have one). \r\n\r\nAlso, a reminder that if you plan to attend our 6pm service launching in Feb, then we have a prayer, planning, and pizza session in the hall this evening - starting at 6pm. \r\n\r\nLooking forward to gathering with you in the Summer sun this arvo!\r\n\r\nBlessings,\r\n', 38, '2022-12-11 09:21:29', NULL);
