INSERT INTO sms (body, sender, created, scheduled_send_at) VALUES ('Hey 6pm Crew! Looking forward to gathering with you this evening. \r\nWhen you rock up, you\'ll hopefully notice some extra lighting. It\'s come to our attention that last Sunday, during the service, someone had their car broken into and stuff stolen from it. \r\nSo, could we please encourage you to:\r\n1. Not leave your valuables in your car - or at least store them out of sight. \r\n2. Make sure your vehicle is locked. \r\n3. Park as close to the hall/lighter areas as possible. \r\n\r\nAlso, to pray for the person that did the thieving. That God would show mercy on them, and they\'d come to know grace and forgiveness in Jesus. \r\n\r\nBless ya\r\n', 38, '2023-08-20 09:11:52', NULL);
