INSERT INTO sms (body, sender, created, scheduled_send_at) VALUES ('Hey SGLs! Because this is the decade that keeps on giving - we have another change. \r\nQuite a few of our SGLs have Covid or are isolating. So, I\'ve decided (in the hopes to get the majority to the meeting) that we will move tomorrow night\'s event to Zoom. Not ideal but this is the new norm. \r\n\r\nIf it\'s ok, I\'ll change to a bit earlier - as there will be no need to travel. \r\n7pm kick-off on this link: https://us02web.zoom.us/j/9876543210\r\n\r\nPlease let me know if there are any problems. \r\nIf you do have Covid and don\'t feel up to jumping in the session then no worries, I\'ll give you a ring on Wednesday. Just let me know. \r\n\r\nOnce again - thanks for your adaptability. \r\n', 38, '2022-01-24 15:13:04', NULL);
