INSERT INTO sms (body, sender, created, scheduled_send_at) VALUES ('Hey church family. Looks like the rain will be holding off (or just missing us to the north!) - so we will be meeting outside under the COLA this arvo at 4pm. There will be some chairs provided but would love you to bring a camping chair if you have one. \r\nMight be wise to bring a mask; in case the weather-people are having an off day and we need to move into the hall!\r\nLooking forward to gathering with you all as we check out the teenage years of Jesus! \r\n', 38, '2022-01-09 13:38:39', NULL);
