INSERT INTO sms (body, sender, created, scheduled_send_at) VALUES ('Hey church!\r\nJust a reminder that this arvo, we are at Bayview Uniting Church for our 4pm service (Corner of Park & Cedar St).\r\nThe Kid\'s Sign-In Table will be in the foyer. Please sign your kids in and then come into the main auditorium with them. We\'ll get them to sit on the floor down the front before they head out to their program.\r\nAlso, we would love for you to bring your Bibles, as all of ours are under the stage at the school! \r\nSee ya there!\r\n\r\nBlessings, ', 38, '2023-07-09 08:46:26', NULL);
