INSERT INTO sms (body, sender, created, scheduled_send_at) VALUES ('Hey church!\r\nLooking forward to gathering with you this arvo at 4pm. \r\n\r\nWe\'ve decided we are going to \'risk it for the biscuit\' and meet outside under the COLA. \r\nThere may be a little sprinkle but nothing like last week and should be nice with the gentle breeze. :) \r\n\r\nHere is the Online Service Program - http://www.gracechurch.example.org/summersessions\r\n\r\nHope to see you there! \r\n\r\nBlessings,\r\n', 38, '2022-03-06 14:32:46', NULL);
