INSERT INTO sms (body, sender, created, scheduled_send_at) VALUES ('Hey church! \r\nLooking forward to seeing you this arvo (4pm) for our Carols service. Yipee!\r\nFeel free to bring a camping chair or two. \r\nWe\'ll be outside under the COLA, and won\'t be serving any hot drinks so if you want tea or coffee, then it\'s a BYO type of situation. :) \r\nAlso, it\'s meant to be a little breeeeeezy. So, it would be a sweet idea to rug up a bit, I reckon!\r\n\r\nHere is the online program (we\'ll have a few hard copies as well).\r\nhttps://www.gracechurch.example.org/carols2022\r\n\r\nCome rejoice and reflect on the greatness of the King of Kings! \r\n\r\nBless ya,\r\n', 38, '2022-12-18 11:25:41', NULL);
