INSERT INTO sms (body, sender, created, scheduled_send_at) VALUES ('Hey church! At the start of Feb next year, we are kicking off 6pm Church - woohoo! \r\nAs we work towards the launch, we\'d love you to come and join us after the 4pm service on Sunday, Dec 11th, for another pizza, planning, and prayer time. \r\nWe\'ll start at 6pm in the school hall - so, if you\'re planning on calling that your service then we would love you to come along. \r\n#reachtheregion #foodbreakisbackbaby ', 38, '2022-11-30 14:48:49', NULL);
