INSERT INTO sms (body, sender, created, scheduled_send_at) VALUES ('Hey church! Happy New Year!\r\n\r\nWhat a cracker way to kick off the year by gathering together this arvo at 4pm. Golden!\r\nThe rain has cleared, so we\'ll be outside under the COLA (would love ya to bring a camping chair if you have one). \r\n\r\nOur Kids Zone Team will run an \'all-in\' style program - with a special guest from France - over January. So, don\'t forget to sign them in when you arrive, and they\'ll head out after the first 3 songs. \r\n\r\nClick below for the online program, or they\'ll be a handful of hard copies for those without phones. \r\nhttps://www.gracechurch.example.org/summersessions\r\n\r\nLooking forward to being with you this arvo! \r\n\r\n', 38, '2023-01-01 13:17:34', NULL);
