INSERT INTO sms (body, sender, created, scheduled_send_at) VALUES ('Hey church! Thanks to those who filled out the Sunday serving survey a few weeks ago - golden stuff! You\'re receiving this because you (or possibly a teen in your household) indicated that they are keen to serve at our rebooted 6pm service. \r\nJust wanted to remind you that after our 4pm service this arvo, we\'ll be gathering to have pizza, do some planning, and spend time praying. \r\nWe\'ll kick off at 6pm and wrap things up by 7pm.\r\nWould lurve to see ya there! \r\n\r\n\r\n', 38, '2022-09-11 10:20:17', NULL);
