INSERT INTO sms (body, sender, created, scheduled_send_at) VALUES ('Hey men of church! Just wanted to draw your attention to two events coming up in our calendar. \r\n\r\nOn Saturday, Aug 26th we have a woodfire pizza night up at Westbrook. \r\n\r\nThen on 17-19 Nov we have another camping weekend up at Sandbar for those interested in getting away for a few days. \r\n\r\nMore details can be found on this link and by clicking on the relevant event tabs. \r\nhttps://www.gracechurch.example.org/men\r\n\r\nWould love to see you at either or both!\r\nBlessings,\r\n', 38, '2023-08-02 09:52:46', NULL);
