INSERT INTO sms (body, sender, created, scheduled_send_at) VALUES ('Hey Parents of church teens!!\r\nWe\'re coming up to the start of the school year and you know what that means. church Youth is back again!! And were starting off with a bang!\r\n\r\nOn the 4th of Feb at 5-8pm, were having the Rockpool Rumble where Yr7-12 students all get to chill, have food together and start the year with a splash. \r\nWe\'d love to see your teens there and to bring their mates along!\r\n\r\nThen on the 11th Feb - our church Groups (Bible Studies) will kick off - each leader will contact you and your teen with details. \r\nWith dinner & Kids Zone (Yr7-10) following at the Scout Hall. (7-9pm)\r\nOur Senior High Group (Yrs 11-12) will have dinner and activities from 7-9pm as well. \r\n\r\nCant wait to kick off the year! \r\n\r\nDaniel Moore (church) - 0491 579 455', 38, '2022-01-26 15:23:02', NULL);
