INSERT INTO sms (body, sender, created, scheduled_send_at) VALUES ('Hey parents of church Youth!\r\n\r\nJust thought I\'d fling you a message in case your teen hasn\'t passed on the flyer from last week. \r\n\r\nThis evening is a guy\'s & girl\'s separate night.\r\n\r\nGIRLS (Yr7-12) will be at the Bayview Point (Main Beach - opposite the Sicilian). \r\n5:30 - 8pm. Bring swimmers, games & $5 for dinner. \r\n\r\nGUYS (Yr 7-12) will be at South Beach park (meeting near the BBQs).\r\n5:30 - 8pm. Bring swimmers, games & $5 for dinner. \r\n\r\nFeel free to contact me with any questions. Or, Kate Miller will be the contact for the girls (0491 577 644)\r\n\r\nHope to see them there! \r\nBlessings,\r\n\r\n(Pastor - church)', 38, '2023-03-10 11:11:11', NULL);
