INSERT INTO sms (body, sender, created, scheduled_send_at) VALUES ('Hey parents of church Youth!\r\nJust to let you know, this Friday night (4th Aug), we have a bonfire up at Cape View (13 Hilltop Drive). \r\n\r\nWe will be meeting at the Scout Hall on River Street at 5:30pm. Leaders will drive the teens up. Returning them to the Scout Hall by 9pm.\r\nDinner will be provided, as per usual. \r\n\r\nIf you live in the Cape View area, could we pretty please ask that you drop your kids straight to the bonfire site at 6pm with pick up being around 8:45pm. \r\n\r\nEmergency contact on the evening will be Kate Miller: 0491577644\r\n\r\nIf the weather is wet, we\'ll still be at the bonfire site - just inside. :) \r\n\r\nBlessings,\r\n ', 38, '2023-08-02 10:08:24', NULL);
