INSERT INTO sms (body, sender, created, scheduled_send_at) VALUES ('Hey Kids Zone Parents!!\r\nWe\'re coming up to the start of the school year and you know what that means; Kids Zone is back again!! \r\nWe kick-off on the 4th February! YOOHOO!\r\n\r\nEvery Friday during Term time at the Scout Hall in Bayview (River St) at 3-5pm. \r\nFor all kids Yr3-6 and we would love them to bring their mates along. \r\nArvo tea, games and Jesus - what more could you want!!\r\n\r\nBless ya,\r\nDaniel Moore & Emily Carter (church)', 38, '2022-01-26 14:00:04', NULL);
