INSERT INTO sms (body, sender, created, scheduled_send_at) VALUES ('Hey Sunday Super Team! Multiple texts in a week! You are blessed... :)\r\nApologies for doing this, but could we please move our 1hr meeting to Sunday, 18th Dec. \r\n9:30-10:30am at the Church Office.\r\nWe have the Carols on later that arvo, but neither  nor I are preaching - so it means we can both be present at the meeting. \r\nPlease let me know if there are any problems with this.\r\n\r\nSo there will be NO meeting this Sunday. \r\nBlessings,\r\n ', 38, '2022-12-01 13:35:49', NULL);
