INSERT INTO sms (body, sender, created, scheduled_send_at) VALUES ('Hey, church 4pmers! \r\n\r\nThe weather is looking real sketchy for this arvo - so praise God that we\'ve just been told we can use the school hall again! God\'s timing is golden!!\r\n\r\nSo, no need to bring a camping chair today. \r\n\r\nDue to the last-minute scramble, we\'ll only have the online program up on the big screen, but if the font is too small, here is the link for your phone - or there\'ll be some hard copies printed out of the songs as well on the info table. \r\nhttps://www.gracechurch.example.org/summersessions\r\n\r\nSee ya this arvo inside-style!\r\n\r\n', 38, '2023-03-12 10:38:43', NULL);
