INSERT INTO sms (body, sender, created, scheduled_send_at) VALUES ('Ladies! I\'ve asked the opinion of some womanly folk at church and they have given the verdict that we would be better off postponing tonight\'s Twilight at the Bullring. Will keep you informed of the new date soon. \r\nApologies for any inconvenience, please pass this on to anyone you\'ve invited. \r\nHave a nice night in!\r\nBlessings,\r\n', 38, '2021-02-13 14:19:26', NULL);
