INSERT INTO sms (body, sender, created, scheduled_send_at) VALUES ('Legends!\r\nA beautiful day to meet together under the COLA at the school. \r\nLooking forward to seeing you at 4pm. \r\nCome and drink from God\'s good Word as we jump into a cracker of a passage. \r\nWould love you to bring a chair to share - if you have one. Here is the link to the online program. \r\nhttps://www.gracechurch.example.org/summersessions\r\n\r\nBlessings,\r\n', 38, '2023-03-05 13:55:07', NULL);
