INSERT INTO sms (body, sender, created, scheduled_send_at) VALUES ('Legends!\r\nLooking forward to gathering with you this arvo at 4pm. \r\n\r\nCracker of a day to be outside in the autumn sun. \r\nHere is this week\'s link to our Online Program.\r\nhttp://www.gracechurch.example.org/summersessions\r\n\r\nWe\'re going to keep the live stream going for the next couple of weeks - so, if you\'re currently in isolation then click this link to join together with us!\r\nhttp://www.gracechurch.example.org/ \r\n\r\nSee ya soon!\r\n', 38, '2022-03-20 14:03:38', NULL);
