INSERT INTO sms (body, sender, created, scheduled_send_at) VALUES ('Tigers! The women of church are having a Twilight @ The Bullring THIS Saturday. Kickoff at 6:30pm. BYO nibblies/dinner/drinks. Have a swim, have a chat, have a laugh, have a pray, bring a mate. Stay as long as you want. A nice and chillaxed evening. \r\nIt\'s potentially drizzling but meant to be warmish. Plus, there\'s a great undercover area with BBQs and benches/tables. \r\nGonna be a cracker!\r\n', 38, '2021-02-10 09:48:57', NULL);
