INSERT INTO sms (body, sender, created, scheduled_send_at) VALUES ('Tigers,\r\nIt\'s with much sadness (but also slight pride in upholding a church tradition)that we have decided to postpone Man Up due to the weather chaos.\r\n\r\nHere\'s what you need to know:\r\nThe NEW date: 5-7 November\r\n\r\nSame Cost: $80 (if you\'ve paid for this one, then we can refund or hold your money - let me know)\r\n\r\nSo, lock that date into your calendars, and a new rego form will come out in late August!\r\n\r\nBlessings,\r\n\r\n', 38, '2021-03-22 10:54:47', NULL);
