INSERT INTO sms (body, sender, created, scheduled_send_at) VALUES ('Hey church! Our tmas Eve service will now be online this year! We\'d love you to join us, 5pm on Friday on our Facebook page. https://www.facebook.com/GraceCommunityChurch\r\nAnd then on tmas morning, (weather permitting) we\'ll be gathering outdoors down at South Beach at 8am, for a BYO everything brekky. So, invite your family, friends & neighbours over for a BBQ this Friday evening and help them rejoice in spite of the weariness our world is feeling! \r\n', 60, '2021-12-22 11:59:38', NULL);
