INSERT INTO sms (body, sender, created, scheduled_send_at) VALUES ('Hey family, this week we\'ll be easing our way back into gathering in person at the school on Sunday. We\'ll start with just our 4pm service. Kids will start in and then head out to their own program.You\'ll need to sign in, and wear masks inside the hall. The School still has some restrictions in place, so we\'ll be live-streaming for those who cannot attend (ie unvaccinated), and also for those who are working, unwell, or still a bit anxious about gathering. There\'ll also be a sausage sizzle afterwards so stick around for a chat. Looking to seeing many of you there. church', 60, '2021-11-19 11:58:51', NULL);
