INSERT INTO sms (body, sender, created, scheduled_send_at) VALUES ('Hi Family. Just a reminder that you have until 5pm today to vote for or against the changes to our constitution. We require at least 50% of formal members to vote and we don\'t have that yet. \r\nYou can read the proposed changes in the email you received 2 weeks ago. If you would like me to send it again, please let me know. You can cast your vote here: https://gracechurch.wufoo.example.com/forms/xuvrap71hhivyg/', 60, '2021-09-22 11:18:02', NULL);
