INSERT INTO sms (body, sender, created, scheduled_send_at) VALUES ('Hey Parents!\r\nPraying that this lock-down isn\'t bringing you down but you\'ll be having a sweet time at home with the fam.\r\nKids Zone won\'t be on this week :( But the leaders are still keen to meet with the youth virtually - so what we are going to do is break up into church Groups and then meet on zoom in those groups for a bit of a chat and a bible study. The church Group leaders will be in touch with the zoom details :)\r\nIf your teen is not in a church Group then let me know and I\'ll get them in one :)\r\nThanks!\r\n', 93, '2021-08-17 09:19:55', NULL);
