INSERT INTO sms (body, sender, created, scheduled_send_at) VALUES ('Hey Church! Just a reminder that we need to manage numbers between our 4pm and 6pm Services as Lakeside Community Hall can only allow 60 adults at a time. To aid us with this you can pre-rego here https://grace.ch/register - there will be plenty of room at 6pm so if you\'re able to shift to that service for a few weeks it would be a great help :) Blessings', 90, '2021-10-03 11:52:41', NULL);
