INSERT INTO sms (body, sender, created, scheduled_send_at) VALUES ('Hey church parents - just a reminder that if your kids are showing any flu-like symptoms (especially cough, sore throat etc) that unfortunately they won\'t be able to attend Kids Zone. Kids are now expected to isolate from school etc with any symptoms until they receive a negative covid test and so we need to follow suit and be above reproach. Thanks for understanding!', 90, '2020-09-04 11:23:48', NULL);
