INSERT INTO sms (body, sender, created, scheduled_send_at) VALUES ('Hey everyone - unfortunately due to the new Covid restrictions here\'s what you need to know about changes to our gatherings today: Masks are required, no congregational singing, 1p/4m2 social distancing is back and kids are gonna start out at kids church.\r\n\r\nUnfortunately you\'ll also need to steer clear if you\'ve got any flu like symptoms or have visited or are hosting visitors from any of the affected areas on or since June 21.\r\n\r\nI know its frustrating but praise God we can still gather in some form! We can still encourage one another and worship God in heaps of ways as we meet this arvo :) \r\n\r\nBlessings', 90, '2021-06-27 11:36:53', NULL);
