INSERT INTO sms (body, sender, created, scheduled_send_at) VALUES ('Hey family! In light of the fires we have decided to cancel the 2pm service today. Instead, we are inviting any who can make it to come to the school hall at 2pm for a short 20min prayer gathering. Then those gathered can head to the homes of anyone else from church whose property sustained damage or may need help to evac and provide any practical help they can. Stay safe and God bless!', 90, '2019-10-27 10:34:14', NULL);
