INSERT INTO sms (body, sender, created, scheduled_send_at) VALUES ('Hey Westbrook crew, we\'re going ahead at the school but we\'ll let you know if anything changes.\r\n\r\nIt will be a small set up (not getting the trailer) and a shorter service. Kids will be in the service today and our collection will go towards the love bomb fund. I\'ll be in touch with anyone on ministries to let you know how the changes effect you :) Blessings', 90, '2019-11-10 10:27:54', NULL);
