INSERT INTO sms (body, sender, created, scheduled_send_at) VALUES ('Hey Westbrook folks - we\'ve lost access to the library for next 3 weeks for kids church so this week we\'ll have a crack at shutting the main door and doing kids church out under cover and on the grass. To make the area a bit more workable, if you\'ve got a picnic blanket or rug that we could borrow for the next few weeks (starting this arvo) that would be amazing! Blessings', 90, '2019-07-07 12:07:16', NULL);
