INSERT INTO sms (body, sender, created, scheduled_send_at) VALUES ('Hi everyone, NSW Health has clarified earlier in the week that the stay at home order for those who\'ve visited affected areas does include other household members. So unfortunately if you\'re 1) unwell or 2) have visited or have visitors from an affected area then the restrictions mean unfortunately you\'ll need to steer clear of our gatherings today :(\r\n\r\nhttps://www.nsw.gov.au/covid-19/rules/what-you-can-do-nsw', 90, '2021-08-08 11:55:48', NULL);
