INSERT INTO sms (body, sender, created, scheduled_send_at) VALUES ('Good morning wonderful people, \r\nJust popping into your inbox to let you know about the next Church seniors social event  \r\n\r\nAnne, Lisa and Marie are organising a barefoot bowling and dinner evening! The plan is to meet at the Ocean Breeze Bowling Club, 8 Ocean Drive Crystal Lake, on Saturday 12th November at 5pm. Followed by dinner together at the Club at 6.30pm - you are more than welcome to join in for both bowls and dinner, or just one. \r\n\r\nBooking is required for the barefoot bowls by next Wednesday - so if you could please let Anne know if you are keen to go along before then, that would be fantastic - 0491 570 110.  \r\n\r\nIf you need help with transport, let Anne know too. The cost for bowls is $5 on the day. \r\n\r\nI am looking forward to hearing all about it!\r\nKate ', 29, '2022-10-27 10:41:47', NULL);
