INSERT INTO sms (body, sender, created, scheduled_send_at) VALUES ('Hey KYCK Kids Zoner\'s!\r\nJust a reminder we are running a bake stall on Easter Sunday to raise money towards us going to KYCK! We\'d love you to bring along some baked goods (cookies, cupcakes, slice... the more the merrier!) to sell & come along on the day to help sell them too! If you could bring your baked goods along to the Bayview Public School hall by 3:45 on Sunday so we can set up the stall before Church, that would be wonderful. Happy baking! :)', 29, '2023-04-05 15:05:13', NULL);
