INSERT INTO sms (body, sender, created, scheduled_send_at) VALUES ('Hey ladies,\r\nStarting from next Tuesday 22nd March, some women from Church will be gathering to fellowship over coffee and cake on the second and fourth Tuesday of every month. Come along and get to know other women in our church family, and feel free to invite a friend or a neighbour along too.\r\nThis week will be at the Peninsula Hotel from 2pm.\r\nHope to see you there :)\r\nKate', 29, '2022-03-18 10:46:26', NULL);
