INSERT INTO sms (body, sender, created, scheduled_send_at) VALUES ('Hey lovely people,\r\nAnother Church in our FIEC network, The Point Community Church in Coffs Harbour, are running a Senior\'s retreat next month from the 10-12 October and have invited other Churches to come along! The speakers are John and Christine Palmer and over the weekend, you\'ll get to fellowship with other seniors, dig into Pauls letter to the Ephesians and enjoy the beauty of Emerald Beach up North. There is one person from church going so far - you can find out more info & rego to join them here :)\r\nhttps://tpcc.elvanto.example.com/form/04c9ebc8-23b3-4c5c-8c08-054357e8418a\r\n\r\nLet me know if you have any questions,\r\nKate', 29, '2023-09-20 14:57:43', NULL);
