INSERT INTO sms (body, sender, created, scheduled_send_at) VALUES ('Hey parents of church Teens!\r\nKids Zone is back this evening for the first time in 2024... and to celebrate, we\'re having a BBQ dinner at the Lakeside Aquatic Centre from 6-8pm! church Groups will start back up next Friday 9th Feb. We\'d love to see your teen(s) and their friends there - let them know to bring swimming gear if they\'re keen to cool down in the water!\r\nWe\'re looking forward to another year of fun & exploring the good news of Jesus together :)\r\n- Kate', 29, '2024-02-02 13:07:28', NULL);
