INSERT INTO sms (body, sender, created, scheduled_send_at) VALUES ('Hey parents of church Youth!\r\nOn Friday 8th March, one of our youth leaders, Andrew, is organising a big \'Amazing Race\' game for Kids Zone and he\'s looking for a few extra helpers on the night to be \'point stops\' or drivers (from 5:30-8pm). If you\'re interested in helping out or have any questions, Andrew would love to hear from you (0491 579 455).\r\n\r\nI\'m looking forward to seeing your teen(s) this Friday at Bayview Public School at the usual 6:45-9pm! :)\r\nKate', 29, '2024-02-28 14:12:50', NULL);
