INSERT INTO sms (body, sender, created, scheduled_send_at) VALUES ('Hey parents of KYCK Kids Zoner\'s!\r\nThere\'s just over 2 weeks until we\'re heading down to Wentworth Falls for KYCK, woohoo!\r\nWe are running an \'overpriced bake stall\' on Easter Sunday to raise money towards our travel costs, and we\'d love your teen(s) to come along and bring some baked goods to sell! \r\nWe\'re aiming to set up the stall by 3:45 on Sunday before Church starts, so if your teen is able to drop the baked goods off to the Bayview Public School hall then, that would be wonderful! Thanks so much!\r\nKate', 29, '2023-04-05 15:22:04', NULL);
